INSERT INTO `geopos_guides` (`id`, `title`, `module`, `lang`, `permission`, `start_url`, `description`, `created_at`, `updated_at`) VALUES
(1, 'Dashboard Overview', 'dashboard', 'english', 'all', NULL, 'A quick tour of your main dashboard.', '2026-02-03 05:22:07', '2026-02-03 05:22:07'),
(2, 'Dashboard Overview (Sinhala)', 'dashboard', 'sinhala', 'all', NULL, 'ඔබගේ ප්‍රධාන පුවරුව පිළිබඳ ඉක්මන් චාරිකාවක්.', '2026-02-03 05:22:07', '2026-02-03 05:22:07'),
(3, 'Financial Overview', 'finance', 'english', 'all', NULL, 'View balances and transactions.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(4, 'මූල්‍ය දළ විශ්ලේෂණය', 'finance', 'sinhala', 'all', NULL, 'ශේෂයන් සහ ගනුදෙනු බලන්න.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(5, 'நிதி கண்ணோட்டம்', 'finance', 'tamil', 'all', NULL, 'நிலுவைகள் மற்றும் பரிவர்த்தனைகளைப் பார்க்கவும்.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(6, 'Employee Management', 'hrm', 'english', 'all', NULL, 'Manage staff and permissions.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(7, 'සේවක කළමනාකරණය', 'hrm', 'sinhala', 'all', NULL, 'සේවකයින් සහ අවසර කළමනාකරණය.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(8, 'பணியாளர் மேலாண்மை', 'hrm', 'tamil', 'all', NULL, 'ஊழியர்கள் மற்றும் அனுமதிகளை நிர்வகித்தல்.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(9, 'Product Management', 'inventory', 'english', 'all', NULL, 'Add, edit and track inventory items.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(10, 'භාණ්ඩ කළමනාකරණය', 'inventory', 'sinhala', 'all', NULL, 'තොග අයිතම එකතු කිරීම සහ නිරීක්ෂණය.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(11, 'தயாரிப்பு மேலாண்மை', 'inventory', 'tamil', 'all', NULL, 'சரக்குகளைச் சேர்க்கவும் மற்றும் கண்காணிக்கவும்.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(12, 'Stock Transfer', 'inventory', 'english', 'all', NULL, 'Move stock between warehouses.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(13, 'තොග මාරු කිරීම', 'inventory', 'sinhala', 'all', NULL, 'ගබඩා අතර තොග මාරු කිරීම.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(14, 'பங்கு பரிமாற்றம்', 'inventory', 'tamil', 'all', NULL, 'கிடங்குகளுக்கு இடையே சரக்குகளை நகர்த்தவும்.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(15, 'Production Overview', 'inventory', 'english', 'all', NULL, 'Track manufacturing and work orders.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(16, 'නිෂ්පාදන දළ විශ්ලේෂණය', 'inventory', 'sinhala', 'all', NULL, 'නිෂ්පාදනය සහ වැඩ ඇණවුම්.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(17, 'உற்பத்தி கண்ணோட்டம்', 'inventory', 'tamil', 'all', NULL, 'உற்பத்தி மற்றும் பணி ஆணைகளை கண்காணிக்கவும்.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(18, 'Reporting Tools', 'reports', 'english', 'all', NULL, 'Generate business insights.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(19, 'වාර්තා මෙවලම්', 'reports', 'sinhala', 'all', NULL, 'ව්‍යාපාරික වාර්තා ලබා ගන්න.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(20, 'அறிக்கையிடல்', 'reports', 'tamil', 'all', NULL, 'வணிக நுண்ணறிவை உருவாக்கவும்.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(21, 'POS Terminal Guide', 'sales', 'english', '1', NULL, 'How to create sales using the POS screen.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(22, 'POS පර්යන්ත මාර්ගෝපදේශය', 'sales', 'sinhala', '1', NULL, 'POS තිරය භාවිතා කර විකුණුම් සිදු කරන ආකාරය.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(23, 'POS முனைய வழிகாட்டி', 'sales', 'tamil', '1', NULL, 'POS திரையைப் பயன்படுத்தி விற்பனை செய்வது எப்படி.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(24, 'Managing Invoices', 'sales', 'english', 'all', NULL, 'View, edit and print invoices.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(25, 'ඉන්වොයිසි කළමනාකරණය', 'sales', 'sinhala', 'all', NULL, 'ඉන්වොයිසි බැලීම, සංස්කරණය සහ මුද්‍රණය.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(26, 'விலைப்பட்டியல் மேலாண்மை', 'sales', 'tamil', 'all', NULL, 'விலைப்பட்டியல்களைப் பார்க்கவும், திருத்தவும் மற்றும் அச்சிடவும்.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(27, 'CRM / Customers', 'sales', 'english', 'all', NULL, 'Manage client profiles and wallet balances.', '2026-02-03 05:50:04', '2026-02-03 05:50:04'),
(28, 'පාරිභෝගික කළමනාකරණය', 'sales', 'sinhala', 'all', NULL, 'පාරිභෝගික විස්තර සහ ශේෂයන්.', '2026-02-03 05:50:05', '2026-02-03 05:50:05'),
(29, 'வாடிக்கையாளர் மேலாண்மை', 'sales', 'tamil', 'all', NULL, 'வாடிக்கையாளர் சுயவிவரங்கள்.', '2026-02-03 05:50:05', '2026-02-03 05:50:05'),
(30, 'Company Settings', 'settings', 'english', '1', NULL, 'Configure your business details.', '2026-02-03 05:50:05', '2026-02-03 05:50:05'),
(31, 'ආයතනයේ සැකසුම්', 'settings', 'sinhala', '1', NULL, 'ව්‍යාපාරික තොරතුරු සකසන්න.', '2026-02-03 05:50:05', '2026-02-03 05:50:05'),
(32, 'நிறுவன அமைப்புகள்', 'settings', 'tamil', '1', NULL, 'வணிக விவரங்களை உள்ளமைக்கவும்.', '2026-02-03 05:50:05', '2026-02-03 05:50:05'),
(33, 'මුල් පිටුව දළ විශ්ලේෂණය', 'dashboard', 'sinhala', 'all', NULL, 'ඔබගේ ව්‍යාපාරයේ සාරාංශය.', '2026-02-03 06:01:34', '2026-02-03 06:01:34'),
(34, 'முகப்புப்பக்கம் கண்ணோட்டம்', 'dashboard', 'tamil', 'all', NULL, 'உங்கள் வணிக சுருக்கம்.', '2026-02-03 06:01:34', '2026-02-03 06:01:34');
