(114, 1, 1, '#dash_0', 'Total Income', 'View your total income stats here.', 'bottom', 1, '2026-02-03 06:42:46'),
(115, 1, 2, '#taskcount', 'Pending Tasks', 'Check your pending to-do list items.', 'left', 1, '2026-02-03 06:42:46'),
