(122, 4, 1, '#accounts_table', 'ගිණුම්', 'සියලුම මූල්‍ය ගිණුම්.', 'bottom', 1, '2026-02-03 06:42:46'),
(123, 4, 2, '.btn-success', 'නව ගනුදෙනුවක්', 'ආදායම් හෝ වියදම් වාර්තා කරන්න.', 'left', 1, '2026-02-03 06:42:46'),
(124, 5, 1, '#accounts_table', 'கணக்குகள்', 'அனைத்து நிதிக் கணக்குகளும்.', 'bottom', 1, '2026-02-03 06:42:46'),
(125, 5, 2, '.btn-success', 'புதிய பரிவர்த்தனை', 'வருமானம் அல்லது செலவைப் பதிவு செய்யவும்.', 'left', 1, '2026-02-03 06:42:46'),
