(136, 11, 1, '.btn-primary.btn-sm.rounded', 'தயாரிப்பு சேர்', 'உங்கள் சரக்குகளில் புதிய உருப்படியைச் சேர்க்கவும்.', 'left', 1, '2026-02-03 06:42:46'),
(137, 11, 2, '#productstable_wrapper', 'சரக்கு பட்டியல்', 'இருக்கும் சரக்குகளைத் தேடுங்கள்.', 'top', 1, '2026-02-03 06:42:46'),
