(160, 26, 1, 'a.btn-primary', 'புதியதை உருவாக்கு', 'புதிய விலைப்பட்டியலை உருவாக்கவும்.', 'left', 1, '2026-02-03 06:42:46'),
(161, 26, 2, '#invoices_wrapper', 'விலைப்பட்டியல் பட்டியல்', 'அனைத்து விலைப்பட்டியல்களையும் தேடவும்.', 'top', 1, '2026-02-03 06:42:46'),
